const input = $input.first().json || {};

function parseIfJsonString(value) {
  if (typeof value !== 'string') return value;
  try {
    return JSON.parse(value);
  } catch {
    return value;
  }
}

function asObject(value) {
  const parsed = parseIfJsonString(value);
  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed;
  return null;
}

const candidates = [
  asObject(input.body),
  asObject(input),
  asObject(input.original_request?.body),
  asObject(input.original_request),
  asObject(input.query),
  asObject(input.parameters)
].filter(Boolean);

let payload = null;
for (const candidate of candidates) {
  if (candidate.data?.source?.itens) {
    payload = candidate;
    break;
  }
}

if (!payload) {
  const bodyObj = asObject(input.body) || {};
  const originalBodyObj = asObject(input.original_request?.body) || {};

  return {
    _valid: false,
    statusCode: 400,
    body: {
      ok: false,
      error: 'Missing required field: data',
      message: 'Payload is empty or does not include data.source.itens',
      diagnostics: {
        received_top_level_keys: Object.keys(asObject(input) || {}),
        body_keys: Object.keys(bodyObj),
        original_body_keys: Object.keys(originalBodyObj),
        content_length: input.original_request?.headers?.['content-length'] || null
      }
    }
  };
}

if (!payload.data?.source || !payload.data.source.itens) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required structure: data.source.itens' }
  };
}

if (!Array.isArray(payload.data.source.itens)) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'itens must be an array' }
  };
}

const itens = payload.data.source.itens;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'input_validated',
  itens_count: itens.length,
  level: 'info'
}));

return { _valid: true, itens };

const ctx = $input.first().json;
const itens = Array.isArray(ctx.itens) ? ctx.itens : [];

function decodeHtml(value) {
  if (typeof value !== 'string') return value;
  return value
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&#x27;/g, "'")
    .replace(/&#x2F;/g, '/')
    .replace(/&nbsp;/g, ' ');
}

function sanitizeForQuery(value) {
  if (typeof value !== 'string') return value;
  return value.replace(/\$/g, '$ ');
}

const transformed = itens
  .map((item) => {
    const data = {};
    for (const key of Object.keys(item || {})) {
      data[key] = sanitizeForQuery(decodeHtml(item[key]));
    }

    const rps = String(data.RPS || '').trim();
    if (!rps) return null;

    return {
      ID: data.ID || null,
      RPS: rps,
      Nota: data.Nota || null,
      Cliente: data.Cliente || null,
      CNPJ: data.CNPJ || null,
      Endereco: data.Endereco || null,
      Numero: data.Numero || null,
      Complemento: data.Complemento || null,
      Bairro: data.Bairro || null,
      Cidade: data.Cidade || null,
      Estado: data.Estado || null,
      CEP: data.CEP || null,
      Email: data.Email || null,
      Telefone: data.Telefone || null,
      Vendedor: data.Vendedor || null,
      ValorServicos: data.ValorServicos || '0',
      ValorTotal: data.ValorTotal || '0',
      TotalParcelas: data.TotalParcelas || null,
      ValorDeducoes: data.ValorDeducoes || null,
      Aliquota: data.Aliquota || null,
      ValorISS: data.ValorISS || '0',
      ISSRetido: data.ISSRetido || null,
      ValorCOFINS: data.ValorCOFINS || '0',
      ValorPIS: data.ValorPIS || '0',
      ValorCSLL: data.ValorCSLL || '0',
      ValorIR: data.ValorIR || '0',
      ValorINSS: data.ValorINSS || '0',
      ValorTributos: data.ValorTributos || '0',
      DataPedido: data.DataPedido || null,
      LocalPrestacao: data.LocalPrestacao || null,
      Contas: data.Contas || null,
      Chave: data.Chave || null,
      Protocolo: data.Protocolo || null,
      Descricao: data.Descricao || null,
      DataEmissao: data.DataEmissao || null,
      Situacao: data.Situacao || null,
      DataCad: data.DataCad || null,
      DataMod: data.DataMod || null
    };
  })
  .filter(Boolean);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'nfs_transformed',
  valid_nfs: transformed.length,
  total_input: itens.length,
  level: 'info'
}));

return transformed;

const upsertRows = $items('Upsert Service NF', 0, 0).map(item => item.json).filter(row => row && row.RPS);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'workflow_completed',
  service_nf_upserted: upsertRows.length,
  level: 'info'
}));

return {
  statusCode: 201,
  body: {
    message: 'GET A NEW regular_bills status '
  }
};

// Erro de validação
const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};

// Extract aggregates with fallback for multiple payload shapes
const upstreamRows = $input.all().map(item => item.json || {});
const transformedRows = $items('Decode + Transform Service NFs', 0, 0).map(item => item.json || {});

const sourceRows = upstreamRows.length ? upstreamRows : transformedRows;

function firstNonEmpty(...values) {
  for (const value of values) {
    const text = String(value || '').trim();
    if (text) return text;
  }
  return '';
}

const codigoCount = {};
for (const row of sourceRows) {
  const codigo = firstNonEmpty(
    row.codigo,
    row.codigo_servico,
    row.id_servico,
    row.RPS,
    row.numero_nf,
    row.Nota
  );

  if (!codigo) continue;
  codigoCount[codigo] = (codigoCount[codigo] || 0) + 1;
}

const aggregates = Object.entries(codigoCount).map(([codigo, count]) => ({
  codigo,
  numeronfs: String(count)
}));

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'aggregates_extracted',
  input_rows: sourceRows.length,
  output_rows: aggregates.length,
  level: 'info'
}));

return aggregates;

// Return the response data as-is
const response = $input.first().json;
return response;
